### 2. Board Class

```python
"""
Represents the 8x8 grid of checkers.
"""

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Place pieces on the board
        colors = ["black", "white"]
        for color in colors:
            row_offset = 1 if color == "black" else 0
            for i in range(3):
                for j in range(8):
                    if (i + j) % 2 == 1 and i >= 3 - row_offset:
                        self.board[i][j] = Piece(color)

    def display(self):
        for row in self.board:
            print(" ".join([p.color[0] if p else "-" for p in row]))
```

